INSERT OR IGNORE INTO doctors (id, hospital_id, name, department, position, phone, email, specialty, influence_level, notes, bio, education, career) VALUES
  (1, 1, '오승하', '이비인후과', '교수', '02-2072-2448', 'ohsh@snu.ac.kr', '인공와우, 이과학, 청각재활', 'high', '인공와우 이식 국내 최다 경험. TODOC 핵심 파트너.', 
   '대한민국 인공와우 이식 분야의 선구자로, 20년간 1,500건 이상의 수술을 집도하였습니다. 소아 양측 인공와우 이식의 국내 프로토콜 수립에 기여하였으며, 다수의 SCI 논문을 발표하고 있습니다.',
   '서울대학교 의과대학 졸업 (2000)\n서울대학교 대학원 의학석사 (2003)\n서울대학교 대학원 의학박사 (2007)\nHouse Ear Institute, Fellowship (2008-2009)',
   '서울대학교병원 이비인후과 전공의 (2001-2005)\n서울대학교병원 이비인후과 임상강사 (2005-2007)\nHouse Ear Institute Fellow (2008-2009)\n서울대학교병원 이비인후과 조교수 (2010-2014)\n서울대학교병원 이비인후과 부교수 (2014-2019)\n서울대학교병원 이비인후과 교수 (2019-현재)\n대한이과학회 이사 (2020-현재)'),
  (2, 1, '이재호', '이비인후과', '부교수', '02-2072-2449', 'leejh@snu.ac.kr', '이과학, 측두골수술, 중이질환', 'medium', '이과 수술 전문. 인공와우 보조 역할.',
   '측두골 수술 및 중이 재건 분야의 전문가입니다. 인공와우 이식 후 합병증 관리와 재수술 경험이 풍부합니다.',
   '서울대학교 의과대학 졸업 (2005)\n서울대학교 대학원 의학박사 (2012)',
   '서울대학교병원 이비인후과 전공의 (2006-2010)\n서울대학교병원 이비인후과 임상강사 (2010-2012)\n서울대학교병원 이비인후과 조교수 (2013-2018)\n서울대학교병원 이비인후과 부교수 (2018-현재)'),
  (3, 2, '정연훈', '이비인후-두경부외과', '교수', '02-3410-3578', 'jungyn@samsung.com', '인공와우, 보청기, 청각재활', 'high', '삼성서울병원 인공와우 프로그램 리더. 핵심 의사결정자.',
   '청각재활 및 인공와우 이식 분야 15년 이상의 경력을 보유하고 있으며, 삼성서울병원 인공와우센터를 설립하여 운영 중입니다. 아시아-태평양 인공와우학회 정회원입니다.',
   '연세대학교 의과대학 졸업 (2002)\n연세대학교 대학원 의학박사 (2009)\nUniversity of Melbourne, Cochlear Implant Fellowship (2010-2011)',
   '삼성서울병원 이비인후과 전공의 (2003-2007)\nUniversity of Melbourne Fellowship (2010-2011)\n삼성서울병원 이비인후과 조교수 (2012-2016)\n삼성서울병원 이비인후과 부교수 (2016-2021)\n삼성서울병원 이비인후과 교수 (2021-현재)\n삼성서울병원 인공와우센터장 (2022-현재)'),
  (4, 2, '박민준', '이비인후-두경부외과', '조교수', '02-3410-3579', 'parkm@samsung.com', '소아 이비인후과, 소아 난청', 'medium', '소아 난청 전문. 젊은 교수로 적극 협력 중.',
   '소아 난청 진단 및 치료에 특화된 전문가로, 신생아 청각 선별검사부터 인공와우 이식까지 소아 청각 재활의 전 과정을 담당하고 있습니다.',
   '성균관대학교 의과대학 졸업 (2010)\n성균관대학교 대학원 의학석사 (2015)',
   '삼성서울병원 이비인후과 전공의 (2011-2015)\n삼성서울병원 이비인후과 임상강사 (2015-2017)\n삼성서울병원 이비인후과 조교수 (2018-현재)'),
  (5, 3, '최병윤', '이비인후과', '교수', '02-2228-3620', 'choiby@yuhs.ac', '인공와우, 이신경학, 어지럼증', 'high', '세브란스 이비인후과 소아 CI 책임자. 학회 발표 활발.',
   '소아 인공와우 이식 국내 톱5 전문의로, 어지럼증과 이신경학 분야에서도 권위를 인정받고 있습니다. 대한이비인후과학회 학술이사를 역임하였습니다.',
   '연세대학교 의과대학 졸업 (1998)\n연세대학교 대학원 의학박사 (2005)\nHarvard Medical School, Research Fellowship (2006-2007)',
   '세브란스병원 이비인후과 전공의 (1999-2003)\n세브란스병원 이비인후과 전임의 (2003-2005)\nHarvard Medical School Fellow (2006-2007)\n세브란스병원 이비인후과 조교수 (2008-2012)\n세브란스병원 이비인후과 부교수 (2012-2017)\n세브란스병원 이비인후과 교수 (2017-현재)\n대한이비인후과학회 학술이사 (2021-2023)'),
  (6, 4, '김형직', '이비인후과', '부교수', '02-3010-3710', 'kimhj@amc.seoul.kr', '인공와우, 이과학', 'medium', '아산병원 인공와우 담당. 안정적 관계.',
   '이과학 및 인공와우 이식 수술 분야에서 10년 이상의 경력을 보유하고 있으며, 특히 성인 인공와우 이식 후 청각재활 프로그램 개발에 기여하고 있습니다.',
   '울산대학교 의과대학 졸업 (2006)\n울산대학교 대학원 의학박사 (2014)',
   '서울아산병원 이비인후과 전공의 (2007-2011)\n서울아산병원 이비인후과 임상강사 (2011-2013)\n서울아산병원 이비인후과 조교수 (2014-2020)\n서울아산병원 이비인후과 부교수 (2020-현재)'),
  (7, 5, '한지원', '이비인후과', '조교수', '031-787-7406', 'hanjw@snubh.org', '소아 난청, 인공와우, 청각학', 'medium', '분당서울대 인공와우 담당. 소아 전문.',
   '분당서울대학교병원에서 소아 난청 클리닉을 운영하고 있으며, 인공와우 이식 후 청각언어재활 프로그램을 주도하고 있습니다.',
   '서울대학교 의과대학 졸업 (2008)\n서울대학교 대학원 의학석사 (2013)',
   '분당서울대병원 이비인후과 전공의 (2009-2013)\n서울대학교병원 이비인후과 임상강사 (2013-2015)\n분당서울대병원 이비인후과 조교수 (2016-현재)'),
  (8, 6, '강수민', '이비인후과', '부교수', '051-240-7335', 'kangsm@pusan.ac.kr', '이과학, 인공와우, 중이수술', 'low', '부산대 인공와우 담당. 영남권 파트너.',
   '영남권에서 인공와우 이식을 시행하는 주요 전문의 중 한 명으로, 중이 재건 수술에도 전문성을 보유하고 있습니다.',
   '부산대학교 의과대학 졸업 (2004)\n부산대학교 대학원 의학박사 (2012)',
   '부산대학교병원 이비인후과 전공의 (2005-2009)\n부산대학교병원 이비인후과 전임의 (2009-2011)\n부산대학교병원 이비인후과 조교수 (2012-2019)\n부산대학교병원 이비인후과 부교수 (2019-현재)');

