INSERT OR IGNORE INTO meetings (id, doctor_id, hospital_id, meeting_date, meeting_type, purpose, content, result, next_action, next_meeting_date) VALUES
  (1, 1, 1, '2026-03-15', 'visit', '신제품 CI 프로세서 소개', '오승하 교수에게 신형 프로세서 CI7000 시제품 시연. 음질 향상과 방수 기능에 관심 표명. 기존 환자 업그레이드 프로그램 문의.', '긍정적 반응. 임상시험 참여 의향 확인.', '임상시험 프로토콜 전달 및 IRB 승인 절차 안내', '2026-04-05'),
  (2, 1, 1, '2026-02-20', 'conference', '2026 대한이과학회 동계학술대회', '오승하 교수 발표 세션 참석. "양측 인공와우 이식의 장기 성적" 주제 발표. 당사 제품 사용 데이터 포함됨. 부스에서 30분간 개별 면담.', '학회 발표에 당사 데이터 인용됨. 양측 이식 시장 확대 논의.', '양측 이식 보험급여 확대 관련 자료 준비', '2026-03-15'),
  (3, 1, 1, '2026-01-10', 'visit', '2026년 연간 계획 미팅', '2025년 실적 리뷰 및 2026년 공동 계획 수립. 연간 150건 이상 수술 예상. 소아 양측 CI 비율 증가 추세 확인.', '2026년 연간 공급계약 갱신 합의.', '계약서 초안 발송', '2026-02-01'),
  (4, 3, 2, '2026-03-20', 'visit', 'CI 센터 개설 1주년 기념 방문', '정연훈 교수와 CI 센터 1주년 성과 리뷰. 연간 수술 80건 달성. 센터 확장 계획 논의.', '센터 확장 시 장비 지원 요청 접수.', '장비 지원 견적서 및 제안서 작성', '2026-04-10'),
  (5, 3, 2, '2026-02-05', 'phone', '학술 심포지엄 기획 협의', '4월 인공와우 심포지엄 공동 개최 논의. 정연훈 교수가 좌장 역할 수락. 해외 연자 초청 관련 협의.', '심포지엄 일정 4월 25일 확정.', '해외 연자 초청장 발송 및 프로그램 구성', '2026-03-20'),
  (6, 5, 3, '2026-03-10', 'visit', '소아 CI 임상 성적 공유', '최병윤 교수 소아 인공와우 장기 추적 데이터 공유. 5세 미만 조기 이식의 언어발달 우수 성적 확인.', '공동 논문 작성 합의.', '논문 초고 데이터 정리 및 공유', '2026-04-15'),
  (7, 5, 3, '2026-01-25', 'conference', 'APSCI 2026 사전 미팅', '아시아-태평양 인공와우학회 발표 준비 관련 미팅. 최병윤 교수 구연 발표 확정.', '학회 발표 자료 지원 합의.', '발표 자료 디자인 및 데이터 분석 지원', '2026-03-10'),
  (8, 6, 4, '2026-03-05', 'visit', '신규 프로세서 시연', '김형직 부교수에게 CI7000 시연. 기존 CI5000 대비 30% 소음환경 음질 개선 데이터 공유.', '환자 10명 업그레이드 트라이얼 진행 합의.', '업그레이드 트라이얼 프로토콜 전달', '2026-04-01'),
  (9, 4, 2, '2026-03-18', 'visit', '소아 난청 조기진단 프로그램 논의', '박민준 교수와 신생아 청각선별검사 결과 인공와우 연계 프로그램 논의. 조기 진단 → 조기 이식 파이프라인 구축 계획.', '파일럿 프로그램 2026 Q3 시작 합의.', '파일럿 프로그램 기획안 작성', '2026-04-20'),
  (10, 7, 5, '2026-02-28', 'visit', '경기남부 소아 CI 현황 점검', '한지원 교수와 경기남부 소아 인공와우 이식 현황 점검. 환자 의뢰 시스템 개선 논의.', '의뢰 시스템 디지털화 합의.', '온라인 의뢰 시스템 데모 준비', '2026-03-30'),
  (11, 8, 6, '2026-02-15', 'online', '영남권 인공와우 현황 리뷰', '강수민 부교수와 영남권 인공와우 시술 현황 온라인 미팅. 연간 20건으로 안정적 유지.', '영남권 수술량 증가 방안 논의 필요.', '환자 교육 세미나 공동 개최 기획', '2026-04-15'),
  (12, 2, 1, '2026-03-25', 'visit', '중이 재건 후 CI 증례 토론', '이재호 부교수와 만성 중이염 수술 후 인공와우 이식 증례 토론. 2-stage 수술 접근법 논의.', '합동 증례 발표 계획 수립.', '증례 보고서 초안 작성', '2026-04-25');

