INSERT OR IGNORE INTO doctor_papers (id, doctor_id, title, journal, year, authors, doi, abstract, paper_type) VALUES
  -- 오승하 교수 논문
  (1, 1, 'Long-term Outcomes of Bilateral Cochlear Implantation in Korean Pediatric Patients', 'Otology & Neurotology', 2025, 'Oh SH, Lee JH, Kim YH, Park JW', '10.1097/MAO.0000000001234', '목적: 한국 소아 환자에서 양측 인공와우 이식의 장기 성적을 분석하였다. 방법: 2010-2020년 양측 이식 아동 120명을 대상으로 CAP, SIR, K-HINT 검사를 시행하였다. 결과: 양측 이식군은 편측군 대비 소음 환경에서 유의하게 우수한 어음인지력을 보였다.', 'journal'),
  (2, 1, 'Cochlear Implant Electrode Insertion Depth and Hearing Preservation: A Prospective Study', 'Hearing Research', 2024, 'Oh SH, Choi BY, Lee JH', '10.1016/j.heares.2024.001', '인공와우 전극 삽입 깊이와 잔존 청력 보존의 관계를 전향적으로 분석한 연구. 360도 이내 삽입 시 저주파 잔존 청력 보존률이 85%에 달함을 확인.', 'journal'),
  (3, 1, 'National Trends in Cochlear Implantation in South Korea: 2015-2024', 'Clinical and Experimental Otorhinolaryngology', 2024, 'Oh SH, Kim HJ, Jung YH, Choi BY, Han JW', '10.21053/ceo.2024.00123', '2015-2024년 건강보험심사평가원 데이터를 활용하여 국내 인공와우 이식 현황을 분석. 환자수 연평균 8.4% 성장, 60세 이상 고령층 이식 급증 추세 확인.', 'journal'),
  (4, 1, '인공와우 이식 후 청각재활 가이드라인 개정안', '대한이비인후과학회지', 2025, '오승하, 정연훈, 최병윤', '', '국내 인공와우 이식 후 청각재활 가이드라인을 개정하여 발표. 소아 및 성인 환자의 연령별, 난청 기간별 맞춤형 재활 프로토콜을 제시.', 'journal'),
  (5, 1, '양측 인공와우 이식의 비용-효과 분석', '대한이과학회 학술대회 발표집', 2026, '오승하, 이재호', '', '양측 인공와우 이식의 비용-효과 분석 결과 발표. QALY 기준 편측 대비 양측 이식의 ICER이 1GDP/capita 이내로 비용-효과적임을 제시.', 'conference'),

  -- 이재호 부교수 논문
  (6, 2, 'Revision Cochlear Implant Surgery: Indications and Outcomes', 'Auris Nasus Larynx', 2024, 'Lee JH, Oh SH, Kim YH', '10.1016/j.anl.2024.001', '인공와우 재이식 수술의 적응증과 성적을 분석. 기기 고장, 감염, 전극 이탈 등 재수술 원인별 청각 성적을 비교.', 'journal'),
  (7, 2, 'Middle Ear Reconstruction Prior to Cochlear Implantation in Chronic Otitis Media', 'Journal of Clinical Medicine', 2025, 'Lee JH, Oh SH', '10.3390/jcm14010001', '만성 중이염 환자에서 인공와우 이식 전 중이 재건 수술의 성적. 2-stage 접근법의 안전성과 효과성을 검증.', 'journal'),

  -- 정연훈 교수 논문
  (8, 3, 'Establishment of Cochlear Implant Center: A Single-Center Experience', 'Journal of Audiology & Otology', 2025, 'Jung YH, Park MJ, Kim SY', '10.7874/jao.2025.001', '삼성서울병원 인공와우센터 설립 후 1년간의 경험을 보고. 연간 80건 수술 달성, 다학제 팀 접근법의 효과성 검증.', 'journal'),
  (9, 3, 'Hearing Rehabilitation and Quality of Life After Cochlear Implantation in Elderly Patients', 'European Archives of Oto-Rhino-Laryngology', 2024, 'Jung YH, Cho YS', '10.1007/s00405-024-001', '65세 이상 고령 환자의 인공와우 이식 후 삶의 질 변화를 분석. GBI, APHAB 등 설문 결과 유의한 삶의 질 향상 확인.', 'journal'),
  (10, 3, 'Cochlear Implant Sound Processor Upgrade: Speech Perception Outcomes', 'Cochlear Implants International', 2025, 'Jung YH, Park MJ, Oh SH', '10.1080/14670100.2025.001', '인공와우 프로세서 업그레이드 후 어음인지력 변화를 분석. 최신 프로세서로 업그레이드 시 소음 환경에서 평균 25% 개선.', 'journal'),

  -- 박민준 조교수 논문
  (11, 4, 'Early Identification and Intervention for Pediatric Hearing Loss: A Korea National Study', 'International Journal of Pediatric Otorhinolaryngology', 2025, 'Park MJ, Jung YH, Cho SJ', '10.1016/j.ijporl.2025.001', '국내 신생아 청각선별검사 후 조기중재 연계 현황 분석. 선별검사 양성 아기의 인공와우 이식까지 평균 소요 시간 분석.', 'journal'),
  (12, 4, '소아 인공와우 이식 후 언어발달 추적 연구', '대한청각학회지', 2024, '박민준, 정연훈', '', '소아 인공와우 이식 후 5년간 언어발달 추적. 2세 이전 이식군에서 생활연령 수준의 언어발달 달성률 80% 이상.', 'journal'),

  -- 최병윤 교수 논문
  (13, 5, 'Vestibular Function After Cochlear Implantation: A Systematic Review', 'Laryngoscope', 2024, 'Choi BY, Han JW, Kim HJ', '10.1002/lary.2024.001', '인공와우 이식 후 전정 기능 변화에 대한 체계적 문헌 고찰. 이식 후 일과성 어지럼증 발생률 30-40%, 영구적 전정 기능 저하 10% 미만.', 'journal'),
  (14, 5, 'Pediatric Cochlear Implantation Under 12 Months: Safety and Outcomes', 'Otology & Neurotology', 2025, 'Choi BY, Oh SH, Jung YH', '10.1097/MAO.0000000005678', '12개월 미만 영아 인공와우 이식의 안전성과 성적. 조기 이식의 언어발달 이점과 수술 합병증률을 분석.', 'journal'),
  (15, 5, 'Neural Response Telemetry Guided Fitting in Pediatric Cochlear Implant Users', 'Cochlear Implants International', 2024, 'Choi BY, Lee KW', '10.1080/14670100.2024.005', 'NRT 기반 소아 인공와우 매핑 방법의 효과성 검증. 행동반응 매핑과 비교하여 유사한 청각 성적 확인.', 'journal'),

  -- 김형직 부교수 논문
  (16, 6, 'Music Perception After Cochlear Implantation: A Cross-sectional Study', 'Frontiers in Neuroscience', 2024, 'Kim HJ, Lee YJ, Kang SM', '10.3389/fnins.2024.001', '인공와우 사용자의 음악 인지 능력 분석. 이식 연수, 음악 훈련 경험이 음악 인지에 미치는 영향을 조사.', 'journal'),
  (17, 6, 'Adult Cochlear Implantation and Cognitive Function Improvement', 'JAMA Otolaryngology', 2025, 'Kim HJ, Oh SH, Choi BY', '10.1001/jamaoto.2025.001', '성인 인공와우 이식 후 인지기능 변화. 65세 이상 이식 환자에서 이식 1년 후 MoCA 점수 유의한 향상 확인.', 'journal'),

  -- 한지원 조교수 논문
  (18, 7, 'Auditory-Verbal Therapy Outcomes in Pediatric CI Users: Regional Hospital Experience', 'Communication Sciences & Disorders', 2025, 'Han JW, Kim MH', '', '지역 거점 병원에서의 소아 인공와우 사용자 청각-구화 치료 성과 보고. 수도권과 비수도권 재활 성과 비교.', 'journal'),

  -- 강수민 부교수 논문
  (19, 8, 'Cochlear Implantation Practice in Regional Center: Challenges and Solutions', 'Korean Journal of Otorhinolaryngology', 2024, 'Kang SM, Park JS', '', '지방 거점 병원 인공와우 이식 프로그램 운영 경험 및 과제. 환자 접근성, 재활 인프라, 전문 인력 부족 문제 분석.', 'journal'),
  (20, 8, 'Hearing Outcomes of Cochlear Implantation in Ossified Cochlea', 'Auris Nasus Larynx', 2025, 'Kang SM, Lee JH', '10.1016/j.anl.2025.002', '골화된 와우에서의 인공와우 이식 성적. Drill-out 기법 사용 시 전극 삽입 성공률과 청각 성적 분석.', 'journal');
